python -c "
import json
from pathlib import Path

base = Path.home() / '.claude' / 'state'
for f in sorted(base.glob('*.json')):
    try:
        d = json.loads(f.read_text(encoding='utf-8'))
        print(f'{f.name}: last_updated={d.get(\"last_updated\", \"MISSING\")}')
        if f.name == 'agent_registry.json':
            print(f'  agents: {[a[\"agent_id\"] for a in d[\"agents\"]]}')
            print(f'  global_metrics: {d[\"global_metrics\"]}')
        elif f.name == 'system_health.json':
            print(f'  overall_state={d[\"overall_state\"]}, rule_count={d[\"rule_count\"]}')
    except Exception as e:
        print(f'{f.name}: ERROR {e}')
"
